  6	import { DataUnavailableError } from '@odf/shared/generic/Error';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { HealthState } from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  Card,
 11	  CardBody,
 12	  Gallery,
 13	  GalleryItem,
 14	  Divider,
 15	  Text,
 16	} from '@patternfly/react-core';
 17	import { DRResourcesContext } from '../dr-dashboard-context';
 18	
 19	type SummaryMap = {
 20	  clusters: {
 21	    totalCount: number;
 22	    withIssuesCount: number;
 23	  };
 24	  applications: {
 25	    totalDiscovredAppsCount: number;
 26	    totalManagedAppsCount: number;
 27	    protectedCount: number;
 28	  };
 29	};
 30	
 31	const getClusterSummary = (
 32	  drClusterAppsMap: DRClusterAppsMap,
 33	  loaded: boolean,
 34	  loadError: any
 35	): SummaryMap => {
 36	  const summaryMap: SummaryMap = {
 37	    clusters: { totalCount: 0, withIssuesCount: 0 },
 38	    applications: {
 39	      totalManagedAppsCount: 0,
 40	      totalDiscovredAppsCount: 0,
 41	      protectedCount: 0,
 42	    },
 43	  };
 44	  if (loaded && !loadError) {
 45	    const drClusters = Object.keys(drClusterAppsMap);
 46	    summaryMap.clusters.totalCount = drClusters?.length;
 47	    drClusters?.forEach((cluster) => {
 48	      summaryMap.applications.totalManagedAppsCount =
 49	        summaryMap.applications.totalManagedAppsCount +
 50	        drClusterAppsMap[cluster].totalManagedAppsCount;
 51	      summaryMap.applications.totalDiscovredAppsCount =
 52	        summaryMap.applications.totalDiscovredAppsCount +
 53	        drClusterAppsMap[cluster].totalDiscoveredAppsCount;
 54	      summaryMap.applications.protectedCount =
 55	        summaryMap.applications.protectedCount +
 56	        drClusterAppsMap[cluster].protectedApps.length;
 57	      const isClusterHealthy = ValidateManagedClusterCondition(
 58	        drClusterAppsMap[cluster]?.managedCluster,
 59	        MANAGED_CLUSTER_CONDITION_AVAILABLE
 60	      );
 61	      if (!isClusterHealthy) {
 62	        summaryMap.clusters.withIssuesCount =
 63	          summaryMap.clusters.withIssuesCount + 1;
 64	      }
 65	    });
 66	  }
 67	  return summaryMap;
 68	};
 69	
 70	export const SummaryCard: React.FC = () => {
 71	  const { t } = useCustomTranslation();
 72	  const { drClusterAppsMap, loaded, loadError } =
 73	    React.useContext(DRResourcesContext);
 74	
 75	  const summaryMap: SummaryMap = getClusterSummary(
 76	    drClusterAppsMap,
 77	    loaded,
 78	    loadError
 79	  );
 80	  const healthyClusters =
 81	    summaryMap.clusters.totalCount - summaryMap.clusters.withIssuesCount;
 82	  const totalAppCount =
 83	    summaryMap.applications.totalDiscovredAppsCount +
 84	    summaryMap.applications.totalManagedAppsCount;
 85	  return (
 86	    <Card data-test="cluster-summary-card">
 87	      <CardBody>
 88	        {loaded && !loadError && (
 89	          <Gallery hasGutter>
 90	            <GalleryItem className="mco-dashboard__contentColumn">
 91	              <Text className="text-muted mco-dashboard__statusText--margin mco-dashboard__statusText--size">
 92	                {t('Clusters')}
 93	              </Text>
 94	              <Text className="mco-dashboard__statusText--margin pf-v6-u-font-size-4xl mco-dashboard__statusText--weight">
 95	                {summaryMap.clusters.totalCount}
 96	              </Text>
 97	              <Text className="text-muted mco-dashboard__statusText--margin">
 98	                {t('in disaster recovery relationship')}
 99	              </Text>
100	              <Divider className="pf-v6-u-w-75 mco-dashboard__statusText--margin" />
101	              <HealthItem
102	                title={t('{{ healthy }} healthy', {
103	                  healthy: healthyClusters,
104	                })}
105	                state={HealthState.OK}
106	                disableDetails={true}
107	                className="text-muted mco-dashboard__statusText--margin"
108	              />
109	              <HealthItem
110	                title={t('{{ issues }} with issues', {
111	                  issues: summaryMap.clusters.withIssuesCount,
112	                })}
113	                state={HealthState.ERROR}
114	                disableDetails={true}
115	                className="text-muted"
116	              />
117	            </GalleryItem>
118	            <GalleryItem className="mco-dashboard__contentColumn">
119	              <Text className="text-muted mco-dashboard__statusText--margin mco-dashboard__statusText--size">
120	                {t('Applications')}
121	              </Text>
122	              <Text className="mco-dashboard__statusText--margin pf-v6-u-font-size-4xl mco-dashboard__statusText--weight">
123	                {totalAppCount}
124	              </Text>
125	              <Text className="text-muted mco-dashboard__statusText--margin">
126	                {t('enrolled in disaster recovery')}
127	              </Text>
128	              <Divider className="pf-v6-u-w-75 mco-dashboard__statusText--margin" />
129	              <Text className="text-muted mco-dashboard__statusText--margin">
130	                {t('ACM discovered applications: {{count}}', {
131	                  count: summaryMap.applications.totalDiscovredAppsCount,
132	                })}
133	              </Text>
134	              <Text className="text-muted">
135	                {t('ACM managed applications: {{count}}', {
136	                  count: summaryMap.applications.totalManagedAppsCount,
137	                })}
138	              </Text>
139	            </GalleryItem>
140	          </Gallery>
141	        )}
142	        {!loaded && !loadError && <DataLoadingState />}
143	        {loadError && loaded && (
144	          <div className="mco-dashboard__centerComponent">
145	            <DataUnavailableError />
146	          </div>
147	        )}
148	      </CardBody>
149	    </Card>
150	  );
151	};
152	
153	const DataLoadingState: React.FC = () => {
154	  return (
155	    <Gallery hasGutter>
156	      <GalleryItem>
157	        <div className="mco-dashboard-loading__singleBlockSmall"></div>
158	      </GalleryItem>
159	      <GalleryItem>
160	        <div className="mco-dashboard-loading__singleBlockSmall"></div>
161	      </GalleryItem>
162	    </Gallery>
163	  );
164	};

